mapper.select:
SELECT count(*) FROM `stationonline_realtime` r LEFT JOIN rtustation as s ON s.stationCode = r.`stationCode` LEFT JOIN HeatExchangeStation as h ON s.stationID = h.id LEFT JOIN company as c ON c.id = h.`companyID` WHERE TRUE
and h.`companyID` = #{companyID}
and r.`stationID` = #{stationID}

SELECT r.`id`, c.id as companyID, c.Name as companyName, s.stationCode as stationCode, s.stationName as stationName, r.`addTime`, r.`offline` FROM `stationonline_realtime` r LEFT JOIN rtustation as s ON s.stationCode = r.`stationCode` LEFT JOIN HeatExchangeStation as h ON s.stationID = h.id LEFT JOIN company as c ON c.id = h.`companyID` WHERE TRUE
and h.`companyID` = #{companyID}
and r.`stationID` = #{stationID}

r.`id`, c.Name as companyName, s.stationCode as stationCode, s.stationName as stationName, r.`addTime`, r.`offline` FROM `stationonline_history` r LEFT JOIN rtustation as s ON s.stationID = r.`stationID` LEFT JOIN HeatExchangeStation as h ON s.stationID = h.id LEFT JOIN company as c ON c.id = h.`companyID` WHERE TRUE
and ( ( h.`companyID` = #{companyID}) OR (c.ParentID = #{companyID} ))
and r.`stationID` = #{stationID}
limit #{offset},#{pageSize}
